create table tb_categoria (atualizado_em TIMESTAMP WITHOUT TIME ZONE, criado_em TIMESTAMP WITHOUT TIME ZONE, id bigint generated by default as identity, nome varchar(255), primary key (id));
create table tb_perfil (id bigint generated by default as identity, nome varchar(255), primary key (id));
create table tb_produto (preco float(53), atualizado_em TIMESTAMP WITHOUT TIME ZONE, criado_em TIMESTAMP WITHOUT TIME ZONE, id bigint generated by default as identity, descricao TEXT, img_url varchar(255), nome varchar(255), primary key (id));
create table tb_produto_categoria (id_categoria bigint not null, id_produto bigint not null, primary key (id_categoria, id_produto));
create table tb_usuario (atualizado_em TIMESTAMP WITHOUT TIME ZONE, criado_em TIMESTAMP WITHOUT TIME ZONE, id bigint generated by default as identity, email varchar(255), nome varchar(255), senha varchar(255), telefone varchar(255), primary key (id));
create table tb_usuario_perfil (id_perfil bigint not null, id_usuario bigint not null, primary key (id_perfil, id_usuario));
alter table if exists tb_produto_categoria add constraint FKqtt9g668uolxpjd42rdb6g7kk foreign key (id_categoria) references tb_categoria;
alter table if exists tb_produto_categoria add constraint FKsf16c80ybln49mop4yex7v7pg foreign key (id_produto) references tb_produto;
alter table if exists tb_usuario_perfil add constraint FKskwwrm4i1ds1ekvp3vf6jj9h4 foreign key (id_perfil) references tb_perfil;
alter table if exists tb_usuario_perfil add constraint FKb82f4fopikpqy2ucxk7osn6y8 foreign key (id_usuario) references tb_usuario;
